const body = $json.body || $json;
const data = body.data || {};
const message = data.message || {};
const key = data.key || {};

const rawMessage = body.sku ?? body.message ?? body.text ?? message.conversation ?? message.extendedTextMessage?.text ?? message.imageMessage?.caption ?? '';
const mensaje = String(rawMessage || '').trim();
const normalized = mensaje.normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();
const upper = normalized.toUpperCase();
const fromMe = key.fromMe === true || body.fromMe === true;
const looksLikeOtp = /CODIGO DE ACCESO RUNNER|EXPIRA EN/i.test(normalized);

const areaAliases = new Map([
  ['FRIO', 'frio'],
  ['SALA', 'sala'],
  ['GM', 'gm'],
]);

let tipo = 'invalid';
let sku = null;
let skus = [];
let area = null;

const parts = normalized.split(',').map((part) => part.trim()).filter(Boolean);
const isValidSkuList = normalized.includes(',') && parts.length > 1 && parts.every((part) => /^\d{6,13}$/.test(part));

if (isValidSkuList) {
  tipo = 'sku_multiple';
  skus = parts;
} else if (/^(SI|S|YES|Y)$/i.test(upper)) {
  tipo = 'yes';
} else if (/^(NO|N)$/i.test(upper)) {
  tipo = 'no';
} else if (areaAliases.has(upper)) {
  tipo = 'area';
  area = areaAliases.get(upper);
} else if (/^[A-Z0-9_-]{2,32}$/.test(upper)) {
  tipo = 'sku';
  sku = upper;
}

if (fromMe || looksLikeOtp) {
  tipo = 'ignore';
}

const remoteJid = body.phone ?? body.telefono ?? key.remoteJid ?? data.remoteJid ?? '';
const telefono = String(remoteJid || '').replace('@s.whatsapp.net', '').replace('@c.us', '').trim();
const instancia = body.instance ?? body.instanceName ?? data.instance ?? '';

return [{
  json: {
    tipo,
    sku,
    skus,
    area,
    telefono,
    instancia,
    mensaje_original: mensaje,
    timestamp: new Date().toISOString()
  }
}];
